#include <stdio.h>

union Data {
   int i;
   float f;
   char str[20];
};

int main() {
   union Data data;
   char type;

   scanf(" %c", &type);

   if (type == 'i') {
      scanf("%d", &data.i);
      printf("%d\n", data.i);
   } else if (type == 'f') {
      scanf("%f", &data.f);
      printf("%f\n", data.f);
   } else if (type == 'c') {
        scanf(" %s", data.str);
        printf("%s\n", data.str);
   }

   return 0;
}
